"const jwt = require('jsonwebtoken');
const User = require('../models/User');

/**
 * Middleware: Protect routes — verifies JWT access token
 */
const protect = async (req, res, next) => {
  let token;

  if (
    req.headers.authorization &&
    req.headers.authorization.startsWith('Bearer ')
  ) {
    token = req.headers.authorization.split(' ')[1];
  }

  if (!token) {
    return res.status(401).json({
      success: false,
      message: 'Access denied. No token provided.',
    });
  }

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    const user = await User.findById(decoded.id).select('-password -refreshToken');

    if (!user) {
      return res.status(401).json({
        success: false,
        message: 'User belonging to this token no longer exists.',
      });
    }

    if (!user.isActive) {
      return res.status(401).json({
        success: false,
        message: 'This account has been deactivated.',
      });
    }

    req.user = user;
    next();
  } catch (err) {
    return res.status(401).json({
      success: false,
      message: err.name === 'TokenExpiredError'
        ? 'Token has expired. Please log in again.'
        : 'Invalid token. Please log in again.',
    });
  }
};

/**
 * Middleware: Require specific plan(s)
 * Usage: requirePlan('pro', 'enterprise')
 */
const requirePlan = (...plans) => {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ success: false, message: 'Authentication required' });
    }

    if (!plans.includes(req.user.plan)) {
      return res.status(403).json({
        success: false,
        message: `This feature requires a ${plans.join(' or ')} plan. Please upgrade your subscription.`,
        currentPlan: req.user.plan,
        requiredPlans: plans,
      });
    }

    next();
  };
};

module.exports = { protect, requirePlan };
"

"const rateLimit = require('express-rate-limit');
const RequestLog = require('../models/RequestLog');

/**
 * General API limiter — 100 requests per 15 minutes
 */
const generalLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: {
    success: false,
    message: 'Too many requests from this IP. Please try again in 15 minutes.',
  },
});

/**
 * Auth routes limiter — 10 requests per 15 minutes
 * Protects against brute-force login attempts
 */
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 10,
  standardHeaders: true,
  legacyHeaders: false,
  message: {
    success: false,
    message: 'Too many authentication attempts. Please wait 15 minutes before trying again.',
  },
});

/**
 * API Proxy limiter — plan-based
 * Free (Starter): 5 requests/minute
 * Pro & Enterprise: unlimited
 */
const proxyLimiter = async (req, res, next) => {
  try {
    if (!req.user) return next();

    // Pro and Enterprise users have no proxy rate limit
    if (req.user.plan !== 'starter') {
      return next();
    }

    // Count requests in the last 60 seconds
    const oneMinuteAgo = new Date(Date.now() - 60 * 1000);
    const requestCount = await RequestLog.countDocuments({
      user: req.user._id,
      createdAt: { $gte: oneMinuteAgo },
    });

    if (requestCount >= 5) {
      return res.status(429).json({
        success: false,
        message: 'Rate limit exceeded. Starter plan allows 5 API requests per minute.',
        hint: 'Upgrade to Pro for unlimited API requests.',
        retryAfter: 60,
      });
    }

    next();
  } catch (err) {
    next(err);
  }
};

module.exports = { generalLimiter, authLimiter, proxyLimiter };
"

